const alert = $input.first().json;
const now = new Date().toISOString();

const severity = (alert.severity || 'unknown').toUpperCase();
const title = alert.title || alert.name || 'Security Alert';
const description = alert.description || alert.message || 'No description provided';
const source = alert.source || alert.engine || 'ALDECI';
const org = alert.org_id || 'default';
const alertId = alert.id || alert.alert_id || 'N/A';
const cvss = alert.cvss_score || alert.risk_score || 'N/A';

const slackPayload = {
  text: `🚨 *CRITICAL SECURITY ALERT* 🚨`,
  attachments: [
    {
      color: '#FF0000',
      blocks: [
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*${title}*\n${description}`
          }
        },
        {
          type: 'fields',
          fields: [
            { type: 'mrkdwn', text: `*Severity:*\n${severity}` },
            { type: 'mrkdwn', text: `*Source:*\n${source}` },
            { type: 'mrkdwn', text: `*Alert ID:*\n${alertId}` },
            { type: 'mrkdwn', text: `*Risk Score:*\n${cvss}` },
            { type: 'mrkdwn', text: `*Org:*\n${org}` },
            { type: 'mrkdwn', text: `*Time:*\n${now}` }
          ]
        },
        {
          type: 'actions',
          elements: [
            {
              type: 'button',
              text: { type: 'plain_text', text: 'View in ALDECI' },
              url: `http://localhost:5173/incident-response?alert_id=${alertId}`,
              style: 'danger'
            }
          ]
        }
      ]
    }
  ]
};

return [{ json: { slackPayload, alert, escalated_at: now } }];
